#include<bits/stdc++.h>
using namespace std;
int n;
double x,a;
int ans=0;
int pf(int s){
	  long long cnt=1;
	  for(int j=1;j<=s;j++){
		  cnt*=2;
	  }
	  return cnt;
}
double p=10;
int d=0;
int main(){
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>x>>a;
		p-=x;
		if(p<=0) break;
		if(p>10) p=10;
		ans+=a;
	}
	int c=0;
	while(1){
		int q=pf(c); 
		if(ans-q>=0){
			ans-=q;
			d++;
		}
		else{
			break;
		}
		c++;
	}
	cout<<d<<" "<<ans<<endl;
	return 0;
}
